// 1. Взимаме индекса на текущото завъртане на ГОЛЕМИЯ цикъл
// Използваме 'Loop Over Items' (първия ти голям цикъл), за да разберем на кой потребител сме в момента
const currentIteration = $('Loop Over Items').context.currentIteration;

// 2. Взимаме данните от Edit Fields5, но филтрирани САМО за това конкретно завъртане
const currentInputs = $input.all().filter(item => item.pairedItem && item.pairedItem.iteration === currentIteration);

// Застраховка: ако n8n няма pairedItem информация, вземи просто текущия входящ масив за тази итерация
const itemsToProcess = currentInputs.length > 0 ? currentInputs : $input.all();

// 3. Обхождаме само филтрираните елементи
return itemsToProcess.map(item => {
  let myRowText = "";

  if (item.json && item.json.incoming_message) {
    myRowText = typeof item.json.incoming_message === 'object' 
      ? (item.json.incoming_message.row || JSON.stringify(item.json.incoming_message)) 
      : item.json.incoming_message;
  } else if (item.json) {
    const firstValue = Object.values(item.json)[0];
    myRowText = typeof firstValue === 'object' ? JSON.stringify(firstValue) : firstValue;
  }

  if (!myRowText || myRowText === "undefined") {
    myRowText = "Празно съобщение / Грешка при четене";
  }

  const formattedOutput = `\n\n● ${myRowText}\n\n`;
  const base64Data = Buffer.from(formattedOutput, 'utf-8').toString('base64');

  return {
    json: { 
      incoming_message: myRowText,
      myRow: formattedOutput
    },
    binary: {
      data: { 
        data: base64Data,
        mimeType: 'text/plain',
        fileName: 'temp_row.txt'
      }
    }
  };
});

const items = $input.all().map(i => i.json);

const historyItems = items.filter(d => d.direction !== undefined);
const correctionItems = items.filter(d => d.correction_note !== undefined);

const historyLines = historyItems.map(d => {
  const who = d.direction === 'outbound' ? 'Support' : 'Customer';
  return `${who}: ${d.body}`;
});
const threadHistoryText = historyLines.length > 0
  ? historyLines.slice(-30).join('\n\n')
  : '(no prior messages in this thread)';

const correctionLines = correctionItems
  .map(d => d.correction_note)
  .filter(Boolean)
  .slice(0, 15);
const correctionPatternsText = correctionLines.length > 0
  ? correctionLines.map(c => `- ${c}`).join('\n')
  : '(no correction history yet for this inbox)';

// The Supabase node has no sort option, so Get Learned Patterns returns every
// row for this client - pick the newest here rather than trusting row order.
const learnedItems = items.filter(d => d.rules !== undefined);
const learnedRulesText = learnedItems.length > 0
  ? [...learnedItems].sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0].rules
  : '';

return [{ json: { threadHistoryText, correctionPatternsText, learnedRulesText } }];

// Draft-vs-final significance gate: only log a correction if the human
// changed >=2% of the reply text (normalized Levenshtein). Skips trivial
// edits (typos, spacing, punctuation) that would otherwise pollute reply_corrections.
const row = $("Get Approved Row").first().json;
const a = String(row.ai_response || "").trim();
const b = String(row.final_response || "").trim();
function lev(s, t) {
  const m = s.length, n = t.length;
  if (!m) return n; if (!n) return m;
  let prev = [], cur = [];
  for (let j = 0; j <= n; j++) prev[j] = j;
  for (let i = 1; i <= m; i++) {
    cur[0] = i;
    for (let j = 1; j <= n; j++) {
      const cost = s[i-1] === t[j-1] ? 0 : 1;
      cur[j] = Math.min(cur[j-1] + 1, prev[j] + 1, prev[j-1] + cost);
    }
    prev = cur.slice();
  }
  return prev[n];
}
const dist = lev(a, b);
const maxLen = Math.max(a.length, b.length) || 1;
const similarity = 1 - dist / maxLen;
if (similarity >= 0.98) {
  return []; // trivial edit -> do not log as a correction
}
return $input.all();
